from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of Triple objects into a single fluent sentence.
    Handles a few common predicates with more natural phrasing;
    falls back to a generic “subject predicate object” pattern.
    """
    if not triples:
        return ""

    parts: list[str] = []
    for t in triples:
        pred = t.predicate
        # Natural phrasing for selected predicates
        if pred == "alternativeName":
            phrase = f"{t.subject} is also known as {t.object}"
        elif pred == "builder":
            phrase = f"{t.subject} was built by {t.object}"
        elif pred == "owner":
            phrase = f"{t.subject} is owned by {t.object}"
        elif pred == "manufacturer":
            phrase = f"{t.subject} was manufactured by {t.object}"
        elif pred == "location":
            phrase = f"{t.subject} is located in {t.object}"
        else:
            # Replace underscores with spaces for readability
            readable_pred = pred.replace("_", " ")
            phrase = f"{t.subject} {readable_pred} {t.object}"
        parts.append(phrase)

    # Join parts into a single sentence
    if len(parts) == 1:
        return parts[0] + "."
    else:
        return ", ".join(parts[:-1]) + ", and " + parts[-1] + "."

# EVOLVE-BLOCK-END

